```javascript
const isDayTime = () => {
  const currentHour = Meta.currentUserTime.hour();
  return currentHour >= 8 && currentHour < 22;
};

const isTweetBySpecificUser = () => {
  const specifiedUser = 'specified_user'; // replace with actual user
  return Twitter.newTweetByUser.UserName === specifiedUser;
};

const isTweetDuringWorkingHours = () => {
  return isDayTime() && isTweetBySpecificUser();
};

const shouldSendNotification = () => {
  return isTweetDuringWorkingHours();
};

const shouldSaveLink = () => {
  return isTweetDuringWorkingHours();
};

if (shouldSendNotification()) {
  IfNotifications.sendNotification.setMessage(Twitter.newTweetByUser.TweetEmbedCode);
  IfNotifications.sendNotification.setHighPriority('high');
}

if (shouldSaveLink()) {
  Feedly.createNewEntryFeedly.setUrl(Twitter.newTweetByUser.LinkToTweet);
}

if (!shouldSendNotification() || !shouldSaveLink()) {
  IfNotifications.sendNotification.skip();
  Feedly.createNewEntryFeedly.skip();
}
```

