```javascript
const userName = 'UserXYZ';
const hashtags = ['#retweet', '#original', '#modified'];
const maxLength = 140;

Twitter.newTweetByUser.filter(tweet => {
  if (tweet.UserName !== userName) return false;

  let modifiedTweet = tweet.Text;
  let symbol = '';
  let hashtag = '';

  if (tweet.Text.includes('RT')) {
    modifiedTweet = modifiedTweet.replace(/@\w+/g, '').replace(/RT\s+@\w+:/, '');
    symbol = String.fromCharCode(Math.floor(Math.random() * 94) + 33);
    hashtag = hashtags[Math.floor(Math.random() * hashtags.length)];
  } else {
    symbol = String.fromCharCode(Math.floor(Math.random() * 94) + 33);
    hashtag = hashtags[Math.floor(Math.random() * hashtags.length)];
  }

  if (modifiedTweet.length + symbol.length + hashtag.length > maxLength) return false;

  modifiedTweet += symbol + ' ' + hashtag;
  Twitter.postNewTweet.setTweet(modifiedTweet);
  return true;
});
```

